<template>
  <div class="cxy_box">
    <header>
      <p @click="$router.back()">
        <img
          src="data:image/png;base64,"
          alt=""
        />
      </p>
      <p>讲师详情</p>
    </header>
    <div class="cxy_base">
      <div>
        <img
          :src="list.avatar"
          alt=""
        />
       <div>
          <p>{{list.real_name}}</p>
        </div>
        <div>
          <van-button round type="info" @click="zqd_guanzhu" v-show="zqd_flag==1">关注</van-button>
          <van-button round type="info" @click="zqd_guanzhu" v-show="zqd_flag==2">取消关注</van-button>

        </div>
      </div>
    </div>
   <div class="cxy_nav">
      <van-tabs v-model="activeName" title-active-color="#eb6100">
        <van-tab title="讲师介绍" name="a">
            <el-row>
            <el-col :span="5">教学年龄</el-col>
            <el-col :span="19">30年</el-col>
            </el-row>
                        <el-row>
            <el-col :span="5">授课价格</el-col>
            <el-col :span="19">400学习币</el-col>
            </el-row>
                        <el-row>
            <el-col :span="5">老师简介</el-col>
            <el-col :span="19">杨老师,特级教师.多次被中国数学会评为全国高中数学竞联赛优秀教练员。长期从事名校理科班的数学教学和数学竞赛辅
                导工作。辅导学生参加全国高中数学联赛有数百人次获全国高中数学联赛一、二、三等奖，数十人被免试保送到清华大学、
                北京大学等名牌大学学习。十多人获CMO获一、二、三等奖，一人获IMO金牌。
                特别是近年来大学试行自主招生，有很多同学通过上他的竞赛辅导课进入清华大学、北京大学、上海交通大学等。</el-col>
            </el-row>
        </van-tab>
        <!-- 主讲课程 -->
        <!-- $router.push('/course-detail') -->
        <van-tab title="主讲课程" name="b">
          <el-card v-for="(item,index) in zqd_arr" :key="index">
            <div @click="zqd_xiangke(item.id)">
              <p>{{ item.title }}</p>
              <p>共{{ item.course_type }}课时</p>
              <div class="cxy_cen">
                <img
                  :src="item.cover_img"
                  alt=""
                />
                <span>{{ item.real_name }}</span>
              </div>
              <div class="cxy_fot">
                <p>{{ item.sales_num }}</p>
                <p>免费</p>
              </div>
            </div>
          </el-card>

        </van-tab>
        <van-tab class="cxy_three" title="学院评价" name="c">
          <el-card>
            <img src="https://wap.365msmk.com/img/empty.0d284c2e.png" alt="" />
            <p>暂无评价</p>
          </el-card>
        </van-tab>
      </van-tabs>
    </div>
    <van-tabbar>
      <van-tabbar-item>立即预约</van-tabbar-item>
    </van-tabbar>
  </div>
</template>

<script>
import {gets,posts} from '../util/api'
export default {
  // 组件名称
  name: "demo",
  // 组件参数 接收来自父组件的数据
  props: {},
  // 局部注册的组件
  components: {},
  // 组件状态值
  data() {
    return {
      activeName: "a",
      list:{},
      // 判断关注和取消关注的flag
      zqd_flag:localStorage.getItem('zqd_flag')||2,
      //这个数组接收主讲课程的数据
      zqd_arr:[]
    };
  },
  // 计算属性
  computed: {},
  // 侦听器
  watch: {},
  // 到这个组件自执行的方法
  async mounted(){
    // 首页列表点击进入详情老师介绍接口
    let {data} = await gets('/api/app/teacher/'+this.$route.query.id)
    this.list = data.data.teacher
    // console.log(this.list)
    //*主讲课程*
    let {data:res} = await posts('/api/app/teacher/mainCourse',{
      limit:10,
      page:1,
      teacher_id:this.$route.query.id
    })
    // console.log(res)
    this.zqd_arr=res.data.list
    console.log(this.zqd_arr)

    // **详情页中评价列表接口**   都是空的  什么评价也没有
       let {data:zqd} = await posts('/api/app/teacher/comment',{
      limit:10,
      page:1,
      teacher_id:this.$route.query.id
    })
        // console.log(zqd)

  },
  // 组件方法
  methods: {
    // 关注与取消关注老师
   async zqd_guanzhu(){
      let {data} =await gets(`/api/app/teacher/collect/${this.$route.query.id}`)
      console.log(data)
      if(data.data.flag==2){
        this.$toast('关注成功')
        this.zqd_flag=data.data.flag
      }else{
        this.$toast('取消关注成功')
        this.zqd_flag=data.data.flag  
      }
      localStorage.setItem('zqd_flag',JSON.stringify(this.zqd_flag))
    },
    zqd_xiangke(i){
        this.$router.push({
          path:'/course-detail',
          query:{
            id:i
          }
        })
    }
  },
};
</script>

